class Solution(object):
    def getSubarrayBeauty(self, nums, k, x):
        # Values are in [-50, 50]; offset by 50 for array indexing
        freq = [0] * 101

        def xth_smallest_neg():
            count = 0
            for v in range(0, 50):  # v represents value v-50 (i.e., -50 to -1)
                count += freq[v]
                if count >= x:
                    return v - 50
            return 0

        result = []
        for i in range(len(nums)):
            freq[nums[i] + 50] += 1
            if i >= k:
                freq[nums[i - k] + 50] -= 1
            if i >= k - 1:
                result.append(xth_smallest_neg())
        return result
